'use client';

import { useEffect, useMemo, useRef, useState } from 'react';
import { Canvas, ThreeEvent, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, PointerLockControls } from '@react-three/drei';
import type { Mesh } from 'three';
import { Vector3 } from 'three';
import type { Exhibit } from '@/types';
import { exhibits } from '@/data/exhibits';
import { ExhibitModal } from '@/components/museum/ExhibitModal';
import { MuseumLegend } from '@/components/museum/MuseumLegend';

const roomSections = [
  { title: 'Quê hương & Tuổi trẻ', x: -9, color: '#3c2a21' },
  { title: 'Hoạt động Cách mạng', x: -1.5, color: '#33251d' },
  { title: 'Kháng chiến chống Pháp', x: 4, color: '#3f2c22' },
  { title: '“Kiến trúc sư” Thống nhất', x: 11.5, color: '#472f24' },
  { title: 'Di sản & Đổi mới', x: 20.5, color: '#39281f' }
];

type ExhibitMeshProps = {
  exhibit: Exhibit;
  onSelect: (exhibit: Exhibit) => void;
};

function ExhibitMesh({ exhibit, onSelect }: ExhibitMeshProps) {
  const meshRef = useRef<Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current) return;
    meshRef.current.position.y = exhibit.position[1] + Math.sin(state.clock.elapsedTime + exhibit.position[0]) * 0.02;
  });

  const geometry = useMemo(() => {
    switch (exhibit.type) {
      case 'radio':
        return <boxGeometry args={exhibit.size ?? [1.2, 0.8, 0.7]} />;
      case 'desk':
        return <boxGeometry args={exhibit.size ?? [2.1, 0.8, 1.2]} />;
      case 'medal':
        return <cylinderGeometry args={[0.6, 0.6, 0.15, 40]} />;
      default:
        return <boxGeometry args={exhibit.size ?? [1.6, 1, 0.08]} />;
    }
  }, [exhibit.size, exhibit.type]);

  const handleClick = (event: ThreeEvent<MouseEvent>) => {
    event.stopPropagation();
    onSelect(exhibit);
  };

  return (
    <group position={exhibit.position}>
      <mesh ref={meshRef} castShadow receiveShadow onClick={handleClick}>
        {geometry}
        <meshStandardMaterial color={exhibit.color} metalness={0.25} roughness={0.5} />
      </mesh>

      <mesh position={[0, -0.55, 0]} rotation={[-Math.PI / 2, 0, 0]}>
        <circleGeometry args={[0.85, 32]} />
        <meshBasicMaterial color="#d6b26f" transparent opacity={0.18} />
      </mesh>
    </group>
  );
}

function FirstPersonController({ enabled }: { enabled: boolean }) {
  const { camera } = useThree();
  const keys = useRef({ forward: false, backward: false, left: false, right: false });

  useEffect(() => {
    if (!enabled) return;

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.code === 'KeyW' || event.code === 'ArrowUp') keys.current.forward = true;
      if (event.code === 'KeyS' || event.code === 'ArrowDown') keys.current.backward = true;
      if (event.code === 'KeyA' || event.code === 'ArrowLeft') keys.current.left = true;
      if (event.code === 'KeyD' || event.code === 'ArrowRight') keys.current.right = true;
    };

    const onKeyUp = (event: KeyboardEvent) => {
      if (event.code === 'KeyW' || event.code === 'ArrowUp') keys.current.forward = false;
      if (event.code === 'KeyS' || event.code === 'ArrowDown') keys.current.backward = false;
      if (event.code === 'KeyA' || event.code === 'ArrowLeft') keys.current.left = false;
      if (event.code === 'KeyD' || event.code === 'ArrowRight') keys.current.right = false;
    };

    window.addEventListener('keydown', onKeyDown);
    window.addEventListener('keyup', onKeyUp);

    return () => {
      window.removeEventListener('keydown', onKeyDown);
      window.removeEventListener('keyup', onKeyUp);
    };
  }, [enabled]);

  useFrame((_, delta) => {
    if (!enabled) return;

    const forward = new Vector3();
    camera.getWorldDirection(forward);
    forward.y = 0;
    forward.normalize();

    const right = new Vector3().crossVectors(forward, camera.up).normalize();
    const move = new Vector3();

    if (keys.current.forward) move.add(forward);
    if (keys.current.backward) move.sub(forward);
    if (keys.current.left) move.sub(right);
    if (keys.current.right) move.add(right);

    if (move.lengthSq() > 0) {
      move.normalize().multiplyScalar(delta * 4.2);
      camera.position.add(move);
      camera.position.x = Math.min(24, Math.max(-13, camera.position.x));
      camera.position.z = Math.min(6, Math.max(-6, camera.position.z));
      camera.position.y = 1.6;
    }
  });

  return enabled ? <PointerLockControls selector="#museum-canvas-wrap" /> : null;
}

function SceneContent({ onSelect, isTouch }: { onSelect: (exhibit: Exhibit) => void; isTouch: boolean }) {
  return (
    <>
      <color attach="background" args={['#0f0b09']} />
      <fog attach="fog" args={['#0f0b09', 14, 45]} />
      <ambientLight intensity={1.15} />
      <hemisphereLight args={['#f4d7b6', '#120f0d', 0.55]} />
      <directionalLight position={[8, 10, 8]} intensity={1.8} castShadow shadow-mapSize-width={1024} shadow-mapSize-height={1024} />

      <mesh position={[6, -0.12, 0]} receiveShadow>
        <boxGeometry args={[40, 0.2, 14]} />
        <meshStandardMaterial color="#1f1712" roughness={0.92} />
      </mesh>

      {roomSections.map((room) => (
        <group key={room.title} position={[room.x, 0, 0]}>
          <mesh position={[0, 0.01, 0]} receiveShadow>
            <boxGeometry args={[6.6, 0.05, 10]} />
            <meshStandardMaterial color={room.color} roughness={0.95} />
          </mesh>
        </group>
      ))}

      <mesh position={[6, 2.2, -5.1]}>
        <boxGeometry args={[40, 4.6, 0.15]} />
        <meshStandardMaterial color="#281d16" roughness={0.9} />
      </mesh>

      <mesh position={[6, 2.2, 5.1]}>
        <boxGeometry args={[40, 4.6, 0.15]} />
        <meshStandardMaterial color="#281d16" roughness={0.9} />
      </mesh>

      {exhibits.map((exhibit) => (
        <ExhibitMesh key={exhibit.id} exhibit={exhibit} onSelect={onSelect} />
      ))}

      {isTouch ? <OrbitControls enablePan={false} maxPolarAngle={Math.PI / 2.1} minDistance={6} maxDistance={18} /> : null}
      <FirstPersonController enabled={!isTouch} />
    </>
  );
}

export function MuseumScene() {
  const [selectedExhibit, setSelectedExhibit] = useState<Exhibit | null>(null);
  const [isTouch, setIsTouch] = useState(false);

  useEffect(() => {
    const detectTouch = () => {
      setIsTouch(window.matchMedia('(pointer: coarse)').matches || window.innerWidth < 992);
    };
    detectTouch();
    window.addEventListener('resize', detectTouch);
    return () => window.removeEventListener('resize', detectTouch);
  }, []);

  return (
    <>
      <div id="museum-canvas-wrap" className="relative h-[72vh] min-h-[540px] overflow-hidden rounded-[2rem] border border-white/10 bg-museum.surface shadow-museum">
        <MuseumLegend />
        <Canvas
          shadows
          dpr={[1, 1.25]}
          gl={{ antialias: false, powerPreference: 'high-performance' }}
          camera={{ position: [-12, 1.6, 0], fov: 58 }}
        >
          <SceneContent onSelect={setSelectedExhibit} isTouch={isTouch} />
        </Canvas>
      </div>

      <div className="mt-6 grid gap-4 md:grid-cols-3">
        <div className="rounded-[1.5rem] border border-white/10 bg-museum.card p-5">
          <p className="text-xs uppercase tracking-[0.24em] text-museum.accent">Lớp nội dung</p>
          <p className="mt-3 text-sm leading-7 text-stone-300">
            Mỗi hiện vật có thể gắn ảnh, video, audio thuyết minh, bản scan tài liệu và liên kết qua trang timeline.
          </p>
        </div>
        <div className="rounded-[1.5rem] border border-white/10 bg-museum.card p-5">
          <p className="text-xs uppercase tracking-[0.24em] text-museum.accent">Tối ưu hiệu suất</p>
          <p className="mt-3 text-sm leading-7 text-stone-300">
            Giai đoạn đầu nên dùng mô hình low-poly, texture nén WebP/AVIF, lazy-load theo phòng và thay dần bằng glTF thật.
          </p>
        </div>
        <div className="rounded-[1.5rem] border border-white/10 bg-museum.card p-5">
          <p className="text-xs uppercase tracking-[0.24em] text-museum.accent">Mở rộng</p>
          <p className="mt-3 text-sm leading-7 text-stone-300">
            Có thể bổ sung audio guide, kiosk video, minimap, hotspot hiện vật và chế độ tham quan tự động cho khách lần đầu.
          </p>
        </div>
      </div>

      <ExhibitModal exhibit={selectedExhibit} onClose={() => setSelectedExhibit(null)} />
    </>
  );
}
